package ru.memearena.battle.api; import java.util.UUID; public record BattleMemeResponse(UUID id,String title,String imageUrl,UUID mediaAssetId,String contentUrl,int rating){ public static BattleMemeResponse from(ru.memearena.meme.domain.Meme m){String cu=m.getMediaAssetId()!=null?"/api/v1/media/"+m.getMediaAssetId()+"/content":m.getImageUrl(); return new BattleMemeResponse(m.getId(),m.getTitle(),m.getImageUrl(),m.getMediaAssetId(),cu,m.getRating());}}
